import requests
from datetime import datetime, timedelta, timezone

def cleanup_stale_devices(token: str, stale_days: int = 90, dry_run: bool = True) -> dict:
    cutoff = (datetime.now(timezone.utc) - timedelta(days=stale_days)).strftime("%Y-%m-%dT%H:%M:%SZ")
    HDR = {"Authorization": f"Bearer {token}"}

    # Find stale enabled devices
    r = requests.get(
        "https://graph.microsoft.com/v1.0/devices",
        headers=HDR,
        params={
            "$filter": f"accountEnabled eq true and approximateLastSignInDateTime le {cutoff}",
            "$select": "id,displayName,approximateLastSignInDateTime,trustType",
            "$top": 999
        }
    )
    stale = r.json().get("value", [])
    stats = {"found": len(stale), "disabled": 0, "errors": 0}

    for device in stale:
        last_seen = device.get("approximateLastSignInDateTime", "never")
        print(f"  {'[DRY RUN] ' if dry_run else ''}Disable: {device['displayName']:<40} last={last_seen[:10]}")
        if not dry_run:
            patch_r = requests.patch(
                f"https://graph.microsoft.com/v1.0/devices/{device['id']}",
                headers={**HDR, "Content-Type": "application/json"},
                json={"accountEnabled": False}
            )
            if patch_r.ok:
                stats["disabled"] += 1
            else:
                stats["errors"] += 1
                print(f"    ERROR: {patch_r.status_code} {patch_r.text}")

    return stats

# Dry run first
stats = cleanup_stale_devices(access_token, stale_days=90, dry_run=True)
print(f"\nWould disable {stats['found']} devices. Re-run with dry_run=False to apply.")

# PowerShell: Create a Conditional Access policy requiring compliant devices
# for all cloud apps (except the CA registration app itself)
# Requires: Policy.ReadWrite.ConditionalAccess

$token = (Get-AzAccessToken -ResourceUrl "https://graph.microsoft.com").Token
$headers = @{ Authorization = "Bearer $token"; "Content-Type" = "application/json" }

$caPolicy = @{
    displayName = "Require Compliant Device - All Cloud Apps"
    state       = "enabledForReportingButNotEnforced"   # audit mode first
    conditions  = @{
        users = @{
            includeUsers  = @("All")
            excludeGroups = @("BREAK-GLASS-GROUP-ID")   # emergency access exclusion
        }
        applications = @{
            includeApplications = @("All")
            excludeApplications = @(
                "0000000a-0000-0000-c000-000000000000"  # MEM enrollment
            )
        }
        platforms = @{
            includePlatforms = @("windows", "macOS", "iOS", "android")
        }
    }
    grantControls = @{
        operator        = "OR"
        builtInControls = @("compliantDevice", "domainJoinedDevice")
    }
} | ConvertTo-Json -Depth 10

$response = Invoke-RestMethod `
    -Uri "https://graph.microsoft.com/v1.0/identity/conditionalAccess/policies" `
    -Method POST `
    -Headers $headers `
    -Body $caPolicy

Write-Output "CA policy created: $($response.id)"
Write-Output "Switch to 'enabled' after validating in report-only mode with Sign-in logs."
